const SUPABASE_URL = 'https://msrsidkrdyzdeatvlgya.supabase.co'
const CONV_HISTORY_UUID = '9fa212b0-501e-4a0d-9018-0ad74d1553df'

let token = ''
for (const key of Object.keys(localStorage)) {
  if (!key.toLowerCase().includes('supabase')) continue
  try {
    const val = JSON.parse(localStorage.getItem(key) || '{}')
    if (val?.access_token) { token = val.access_token; break }
  } catch { }
}

const message = variables[/* messageEnvoi */'f3d0889e-18f3-474c-b15d-820947086bec']
const history = variables[/* conversationHistory */'9fa212b0-501e-4a0d-9018-0ad74d1553df'] || []
const assistantId = variables[/* activeAssistantId */'36ad1a9a-24e3-4ebf-b42a-b5dc53163077']
const userId = variables[/* monProfil */'62bb377c-a846-4aaf-a343-c22062d2769b']?.[0]?.['id']

let currentHistory = [
  ...history,
  { role: 'user', content: message },
  { role: 'assistant', content: '' }
]
wwLib.wwVariable.updateValue(CONV_HISTORY_UUID, currentHistory)

const response = await fetch(`${SUPABASE_URL}/functions/v1/chat-ai`, {
  method: 'POST',
  headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${token}` },
  body: JSON.stringify({ assistant_id: assistantId, message: message, history: history, user_id: userId, stream: true })
})

const reader = response.body.getReader()
const decoder = new TextDecoder()
let assistantContent = ''
let buffer = ''

while (true) {
  const { done, value } = await reader.read()
  if (done) break
  buffer += decoder.decode(value, { stream: true })
  const lines = buffer.split('\n')
  buffer = lines.pop()
  for (const line of lines) {
    if (!line.startsWith('data: ')) continue
    const data = line.slice(6).trim()
    if (data === '[DONE]') continue
    try {
      const parsed = JSON.parse(data)
      if (parsed.delta) {
        assistantContent += parsed.delta
        const updated = [...currentHistory]
        updated[updated.length - 1] = { role: 'assistant', content: assistantContent }
        currentHistory = updated
        wwLib.wwVariable.updateValue(CONV_HISTORY_UUID, updated)
      }
    } catch { }
  }
}

