const isRecording = window._mediaRecorder && window._mediaRecorder.state === 'recording'
if (isRecording) {
  window._mediaRecorder.stop()
} else {
  const stream = await navigator.mediaDevices.getUserMedia({ audio: true })
  const mediaRecorder = new MediaRecorder(stream)
  window._mediaRecorder = mediaRecorder
  window._audioChunks = []
  mediaRecorder.ondataavailable = (e) => { window._audioChunks.push(e.data) }
  mediaRecorder.onstop = async () => {
    const audioBlob = new Blob(window._audioChunks, { type: 'audio/webm' })
    const arrayBuffer = await audioBlob.arrayBuffer()
    const bytes = new Uint8Array(arrayBuffer)
    let binary = ''
    for (let i = 0; i < bytes.byteLength; i++) { binary += String.fromCharCode(bytes[i]) }
    const base64 = btoa(binary)
